def process_data(mapping, sequence):
    score = 0
    modifier = 1
    for num in sequence:
        if num in mapping:
            operation = mapping[num]
            if operation == 'add':
                score += (num + modifier)
            elif operation == 'sub':
                score -= (num - modifier)
            elif operation == 'mul':
                # This operation only changes the modifier for subsequent steps
                modifier = num
        else:
            # If the number is not in the map, penalize the score
            # and reset the modifier.
            score -= modifier
            modifier = 1

op_map = {
    3: 'add',
    5: 'mul',
    2: 'sub',
    7: 'add'
}
num_seq = [3, 5, 4, 2, 7]

print(process_data(op_map, num_seq))
